<?php if(!empty($alerts)):?><div class="alert alert-warning"><strong><i class="fa-solid fa-triangle-exclamation me-2"></i>Certifications expiring within 60 days</strong><ul class="mb-0 mt-2"><?php foreach($alerts as $a):?><li><?=e($a['user_name'])?>: <?=e($a['certification_name'])?> on <?=e($a['expires_date'])?></li><?php endforeach?></ul></div><?php endif?><div class="row g-4"><div class="col-lg-4"><div class="card shadow-sm"><div class="card-body"><h1 class="h4">Add Certification</h1><form method="post" action="/portal/certifications" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Employee</label><select name="user_id" class="form-select"><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Certification</label><input name="certification_name" class="form-control" required></div><div class="col-12"><label class="form-label">Issuer</label><input name="issuing_organization" class="form-control"></div><div class="col-12"><label class="form-label">Credential Number</label><input name="credential_number" class="form-control"></div><div class="col-6"><label class="form-label">Issued</label><input type="date" name="issued_date" class="form-control"></div><div class="col-6"><label class="form-label">Expires</label><input type="date" name="expires_date" class="form-control"></div><div class="col-12"><label class="form-label">Notes</label><textarea name="notes" class="form-control"></textarea></div><div class="col-12"><button class="btn btn-primary w-100">Add Certification</button></div></form></div></div></div><div class="col-lg-8"><div class="card shadow-sm"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Employee</th><th>Certification</th><th>Issuer</th><th>Expires</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($certifications as $c):?><tr><td><?=e($c['user_name'])?></td><td><strong><?=e($c['certification_name'])?></strong><div class="small text-muted"><?=e($c['credential_number']??'')?></div></td><td><?=e($c['issuing_organization']??'')?></td><td><?=e($c['expires_date']??'Never')?><?php if($c['days_remaining']!==null && $c['days_remaining']>=0 && $c['days_remaining']<=60):?><div class="small text-warning"><?=$c['days_remaining']?> days</div><?php endif?></td><td><span class="badge text-bg-<?=$c['status']==='active'?'success':'secondary'?>"><?=e($c['status'])?></span></td><td><form method="post" action="/portal/certifications/<?=$c['id']?>/status" class="d-flex gap-2"><?=csrf_field()?><select name="status" class="form-select form-select-sm"><option>active</option><option>expired</option><option>suspended</option><option>revoked</option></select><button class="btn btn-sm btn-outline-secondary">Update</button></form><button type="button" class="btn btn-sm btn-outline-primary mt-1" data-cert-upload="<?=$c['id']?>"><i class="fa-solid fa-upload"></i> Document</button><form method="post" action="/portal/certifications/<?=$c['id']?>/renewal" class="d-inline"><?=csrf_field()?><button class="btn btn-sm btn-outline-warning mt-1"><i class="fa-solid fa-rotate"></i> Renew</button></form></td></tr><?php endforeach?></tbody></table></div></div></div></div>
<div class="portal-card mt-4"><div class="card-header-row"><div><h2>Renewal Workflows</h2><p>Track expiring credentials through renewal and approval.</p></div></div><div class="table-responsive"><table class="table portal-table"><thead><tr><th>Certification</th><th>Assigned</th><th>Target</th><th>Status</th><th>Notes</th><th></th></tr></thead><tbody><?php foreach(($renewals??[]) as $r):?><tr><form method="post" action="/portal/certification-renewals/<?=$r['id']?>"><?=csrf_field()?><td><?=e($r['certification_name'])?></td><td><?=e($r['assigned_name']??'')?><input type="hidden" name="assigned_to" value="<?=e($r['assigned_to'])?>"></td><td><input class="form-control form-control-sm" type="date" name="target_date" value="<?=e($r['target_date'])?>"></td><td><select class="form-select form-select-sm" name="status"><?php foreach(['requested','in_progress','submitted','approved','rejected','cancelled'] as $v):?><option value="<?=$v?>" <?=$r['status']===$v?'selected':''?>><?=ucwords(str_replace('_',' ',$v))?></option><?php endforeach?></select></td><td><input class="form-control form-control-sm" name="notes" value="<?=e($r['notes'])?>"></td><td><button class="btn btn-sm btn-outline-primary">Save</button></td></form></tr><?php endforeach?><?php if(empty($renewals)):?><tr><td colspan="6" class="text-center text-muted py-4">No renewal workflows yet. Use the Renew button on a certification.</td></tr><?php endif?></tbody></table></div></div>
<div class="portal-card mt-4"><div class="card-header-row"><div><h2>Certification Documents</h2><p>Store certificates, cards, and supporting credentials.</p></div></div><div class="table-responsive"><table class="table portal-table"><thead><tr><th>Certification</th><th>File</th><th>Uploaded</th><th></th></tr></thead><tbody><?php foreach(($documents??[]) as $d):?><tr><td><?=e($d['certification_name'])?></td><td><?=e($d['filename'])?></td><td><?=e($d['created_at'])?></td><td><a class="btn btn-sm btn-outline-primary" href="/portal/certification-documents/<?=$d['id']?>">Download</a></td></tr><?php endforeach?><?php if(empty($documents)):?><tr><td colspan="4" class="text-center text-muted py-4">No certification documents uploaded.</td></tr><?php endif?></tbody></table></div></div>
<script>document.addEventListener('DOMContentLoaded',()=>{document.querySelectorAll('[data-cert-upload]').forEach(btn=>btn.addEventListener('click',()=>{const id=btn.dataset.certUpload;const form=document.createElement('form');form.method='post';form.enctype='multipart/form-data';form.action='/portal/certifications/'+id+'/documents';form.innerHTML='<?=str_replace("'","\\'",csrf_field())?><input type="file" name="document" accept="application/pdf,image/jpeg,image/png" required><button>Upload</button>';form.style.display='none';document.body.appendChild(form);form.querySelector('input').click();form.querySelector('input').addEventListener('change',()=>form.submit());}));});</script>
